// Get all input items (contacts) from the previous node
const inputItems = $input.all();
console.log('Received', inputItems.length, 'input items');

// Email validation regex - must have @ and at least one dot after @
const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

// Process each contact and validate email format
return inputItems.map(item => {
  const contact = item.json;
  const email = contact.email;

  console.log('Processing contact:', contact.firstName, contact.lastName, 'Email:', email);

  // Check if email is valid format:
  // - Must not be null or undefined
  // - Must be a string
  // - Must not be empty or just whitespace
  // - Must match email regex pattern
  const isValidFormat = email !== null && 
                       email !== undefined && 
                       typeof email === 'string' && 
                       email.trim() !== '' && 
                       emailRegex.test(email.trim());

  return {
    json: {
      ...contact,
      email: email || '',
      isValidFormat: isValidFormat,
      originalEmail: email,
      processStatus: 'format_validated',
      validationReason: !email || email === '' ? 'empty_email' :
                       email === null ? 'null_email' :
                       typeof email !== 'string' ? 'non_string_email' :
                       !emailRegex.test(email.trim()) ? 'invalid_format' :
                       'valid_format'
    }
  };
});

// Mock email lookup response
