  }
};

// Final processing and categorization
const items = $input.all();

const validEmails = [];
const invalidEmails = [];

items.forEach(item => {
  const data = item.json;

  // Determine final category
  if ((data.verified === true) || (data.lookupSuccess === true && data.confidence > 0.7)) {
    validEmails.push({
      ...data,
      finalCategory: 'valid',
      finalEmail: data.finalEmail || data.email,
      source: data.verified ? 'verified' : 'lookup'
    });
  } else {
    invalidEmails.push({
      ...data,
      finalCategory: 'invalid',
      finalEmail: data.finalEmail || data.originalEmail || '',
      source: data.processStatus || 'unknown'
    });
  }
});

return [
  {
    json: {
      validEmails: validEmails,
      invalidEmails: invalidEmails,
      summary: {
        totalProcessed: items.length,
        validCount: validEmails.length,
        invalidCount: invalidEmails.length,
        verifiedCount: validEmails.filter(e => e.source === 'verified').length,
        lookupSuccessCount: validEmails.filter(e => e.source === 'lookup').length
      }
    }
  }
];

// Domain Model: Domain Lookup Enhancement Workflow
// Takes existing data and adds domain information when company field exists
// Input: any data that might have a company field
// Output: same data enhanced with domain information

// Configuration
const TOMBA_CONFIG = {
  domainSearchUrl: 'https://api.tomba.io/v1/domain-search',
  headers: {
    'content-type': 'application/json',
    'X-Tomba-Key': 'ta_keh9lvy67waoa6eqbibpobfm1nr85ylm6dirx',
    'X-Tomba-Secret': 'ts_dbd0e719-5c2e-4c4b-8c6f-6bbba25da7a0'
  }
};

// Helper Functions
function extractDomainFromEmail(email) {
  try {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!emailRegex.test(email)) {
      throw new Error('Invalid email format');
    }
    return email.split('@')[1];
  } catch (error) {
    throw new Error(`Cannot extract domain from email "${email}": ${error.message}`);
  }
}

function extractCompanyFromDomain(domain) {
  try {
    // Remove common TLDs and get the main part
    const mainPart = domain.replace(/\.(com|org|net|edu|gov|mil|int|co\.uk|co\.jp|de|fr|it|es|ru|cn|in|au|ca|br)$/i, '');

    // Capitalize first letter
    return mainPart.charAt(0).toUpperCase() + mainPart.slice(1);
  } catch (error) {
    return domain;
  }
}

async function findDomainByCompany(companyName) {
  try {
    const params = [
      `website=${encodeURIComponent(companyName.trim())}`,
      `department=executive`
    ].join('&');

    const url = `${TOMBA_CONFIG.domainSearchUrl}?${params}`;

    const response = await this.helpers.httpRequest({
      method: 'GET',
      url: url,
      headers: TOMBA_CONFIG.headers,
      json: true,
      resolveWithFullResponse: true
    });

    const responseData = response.body?.data;
    const domains = responseData?.domains || [];
    const primaryDomain = domains.length > 0 ? domains[0] : null;
    const organization = responseData?.organization || null;

    return {
      success: true,
      primaryDomain: primaryDomain,
      allDomains: domains,
      organization: organization,
      totalDomains: domains.length,
      statusCode: response.statusCode
    };

  } catch (error) {
    return {
      success: false,
      primaryDomain: null,
      allDomains: [],
      organization: null,
      totalDomains: 0,
      error: error.message,
      errorType: error.name || 'DomainSearchError',
      statusCode: error.statusCode || null
    };
  }
}

// Main Processing Logic
async function processData() {
  let items = [];
  let results = [];

  try {
    // Input validation
    const inputData = $input.all();

    if (!inputData || inputData.length === 0) {
      throw new Error('No input data received');
    }

    // Extract items - handle different input structures
    if (inputData.length > 1) {
      items = inputData.map(item => item.json);
    } else if (Array.isArray(inputData[0].json)) {
      items = inputData[0].json;
    } else {
      items = [inputData[0].json];
    }

    if (!Array.isArray(items) || items.length === 0) {
      throw new Error('No items found in input data');
    }

    console.log(`Processing ${items.length} items for domain lookup`);

    // Process each item
    for (let i = 0; i < items.length; i++) {
      const item = items[i];

      // Build base result object (keep all original data)
      const result = {
        ...item,
        processedAt: new Date().toISOString(),
        itemIndex: i + 1,
        totalItems: items.length
      };

      // Debug: Check what fields we have
      console.log(`Item ${i + 1} debug:`, {
        hasCompany: !!item.company,
        companyValue: item.company,
        hasEmail: !!item.email,
        emailValue: item.email
      });

      // Check if item has company field OR email field (to extract company info)
      if (item.company?.trim()) {
        console.log(`Item ${i + 1}: Finding domain for company "${item.company}"`);

        try {
          const domainResult = await findDomainByCompany(item.company);

          if (domainResult.success && domainResult.primaryDomain) {
            result.domainStatus = 'domain_found';
            result.primaryDomain = domainResult.primaryDomain;
            result.allDomains = domainResult.allDomains;
            result.organization = domainResult.organization;
            result.totalDomains = domainResult.totalDomains;
            result.apiStatusCode = domainResult.statusCode;
            result.searchMethod = 'company_field';

            console.log(`Item ${i + 1}: Found domain "${domainResult.primaryDomain}" for "${item.company}"`);
          } else if (domainResult.success) {
            result.domainStatus = 'no_domain_found';
            result.primaryDomain = null;
            result.allDomains = [];
            result.organization = domainResult.organization;
            result.totalDomains = 0;
            result.apiStatusCode = domainResult.statusCode;
            result.searchMethod = 'company_field';

            console.log(`Item ${i + 1}: No domain found for "${item.company}"`);
          } else {
            result.domainStatus = 'search_failed';
            result.primaryDomain = null;
            result.allDomains = [];
            result.organization = null;
            result.totalDomains = 0;
            result.error = domainResult.error;
            result.errorType = domainResult.errorType;
            result.apiStatusCode = domainResult.statusCode;
            result.searchMethod = 'company_field';

            console.log(`Item ${i + 1}: Domain search failed for "${item.company}": ${domainResult.error}`);
          }
        } catch (searchError) {
          result.domainStatus = 'processing_error';
          result.primaryDomain = null;
          result.allDomains = [];
          result.error = searchError.message;
          result.errorType = searchError.name || 'ProcessingError';
          result.searchMethod = 'company_field';

          console.log(`Item ${i + 1}: Processing error for "${item.company}": ${searchError.message}`);
        }
      } else if (item.email?.trim()) {
        // No company field, but has email - try to extract company from domain
        try {
          const emailDomain = extractDomainFromEmail(item.email);
          const guessedCompany = extractCompanyFromDomain(emailDomain);

          console.log(`Item ${i + 1}: No company field, trying to find company info for domain "${emailDomain}" (guessed: "${guessedCompany}")`);

          const domainResult = await findDomainByCompany(guessedCompany);

          if (domainResult.success && domainResult.primaryDomain) {
            result.domainStatus = 'domain_found';
            result.primaryDomain = domainResult.primaryDomain;
            result.allDomains = domainResult.allDomains;
            result.organization = domainResult.organization;
            result.totalDomains = domainResult.totalDomains;
            result.apiStatusCode = domainResult.statusCode;
            result.searchMethod = 'extracted_from_email';
            result.extractedDomain = emailDomain;
            result.guessedCompany = guessedCompany;

            console.log(`Item ${i + 1}: Found company info for "${guessedCompany}" (from email domain)`);
          } else if (domainResult.success) {
            result.domainStatus = 'no_domain_found';
            result.primaryDomain = emailDomain; // Use the email domain as fallback
            result.allDomains = [emailDomain];
            result.organization = domainResult.organization;
            result.totalDomains = 1;
            result.apiStatusCode = domainResult.statusCode;
            result.searchMethod = 'extracted_from_email';
            result.extractedDomain = emailDomain;
            result.guessedCompany = guessedCompany;

            console.log(`Item ${i + 1}: No company info found, using email domain "${emailDomain}" as fallback`);
          } else {
            result.domainStatus = 'search_failed';
            result.primaryDomain = emailDomain; // Use the email domain as fallback
            result.allDomains = [emailDomain];
            result.organization = null;
            result.totalDomains = 1;
            result.error = domainResult.error;
            result.errorType = domainResult.errorType;
            result.apiStatusCode = domainResult.statusCode;
            result.searchMethod = 'extracted_from_email';
            result.extractedDomain = emailDomain;
            result.guessedCompany = guessedCompany;

            console.log(`Item ${i + 1}: Company search failed, using email domain "${emailDomain}" as fallback`);
          }
        } catch (extractError) {
          result.domainStatus = 'extraction_error';
          result.primaryDomain = null;
          result.allDomains = [];
          result.error = extractError.message;
          result.errorType = extractError.name || 'ExtractionError';
          result.searchMethod = 'extracted_from_email';

          console.log(`Item ${i + 1}: Failed to extract domain from email: ${extractError.message}`);
        }
      } else {
        // No company field and no email - just pass through the data
        result.domainStatus = 'no_searchable_fields';
        console.log(`Item ${i + 1}: No company or email field, passing through unchanged`);
      }

      results.push({ json: result });
    }

    const withSearchableFields = results.filter(r => r.json.domainStatus && !['no_searchable_fields'].includes(r.json.domainStatus)).length;
    const domainsFound = results.filter(r => r.json.domainStatus === 'domain_found').length;
    const emailExtracted = results.filter(r => r.json.searchMethod === 'extracted_from_email').length;

    console.log(`Domain lookup complete: ${results.length} items processed`);
    console.log(`- Items with searchable fields: ${withSearchableFields}`);
    console.log(`- Domains found: ${domainsFound}`);
    console.log(`- Company info extracted from email: ${emailExtracted}`);
    console.log(`- Items passed through unchanged: ${results.length - withSearchableFields}`);

    return results;

  } catch (error) {
    console.log('Workflow error occurred:', error.message);

    return [{
      json: {
        domainStatus: 'workflow_error',
        error: error.message,
        errorType: error.name || 'UnknownError',
        processedAt: new Date().toISOString(),
        totalItemsExpected: items?.length || 0
      }
    }];
  }
}

// Execute the workflow
return await processData();
